Use ASP.NET Core's **`WebApplicationFactory<T>`** — it hosts your app in-process with a test HTTP pipeline (no real network port).

### Setup

```bash
dotnet add package Microsoft.AspNetCore.Mvc.Testing
dotnet add package xunit
```

### Test class

```csharp
public class McpIntegrationTests : IClassFixture<WebApplicationFactory<Program>>
{
    private readonly HttpClient _client;

    public McpIntegrationTests(WebApplicationFactory<Program> factory)
    {
        _client = factory.CreateClient();
    }

    [Fact]
    public async Task Initialize_ReturnsServerCapabilities()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 1,
            method = "initialize",
            @params = new
            {
                protocolVersion = "2025-03-26",
                capabilities = new { },
                clientInfo = new { name = "test-client", version = "1.0" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        Assert.Equal("2.0", body.GetProperty("jsonrpc").GetString());
        Assert.Equal(1, body.GetProperty("id").GetInt32());
        Assert.True(body.GetProperty("result").TryGetProperty("capabilities", out _));
    }

    [Fact]
    public async Task ToolsList_ReturnsRegisteredTools()
    {
        var request = new { jsonrpc = "2.0", id = 2, method = "tools/list" };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        response.EnsureSuccessStatusCode();
        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var tools = body.GetProperty("result").GetProperty("tools");
        Assert.True(tools.GetArrayLength() > 0);
    }

    [Fact]
    public async Task ToolsCall_ExecutesTool()
    {
        var request = new
        {
            jsonrpc = "2.0",
            id = 3,
            method = "tools/call",
            @params = new
            {
                name = "my-tool",
                arguments = new { input = "hello" }
            }
        };

        var response = await _client.PostAsJsonAsync("/mcp", request);

        var body = await response.Content.ReadFromJsonAsync<JsonElement>();
        var result = body.GetProperty("result");
        Assert.False(result.GetProperty("isError").GetBoolean());
    }
}
```

### Key points

- **`WebApplicationFactory<Program>`** boots your entire middleware pipeline in-memory — no port, no network.
- Override services (e.g., swap a real DB for an in-memory one) via `factory.WithWebHostBuilder(b => b.ConfigureServices(...))`.
- If your MCP endpoint uses **SSE** for streaming, read the response stream with `HttpCompletionOption.ResponseHeadersRead` and parse SSE events line-by-line.
- Make sure `Program` is accessible to your test project (add `InternalsVisibleTo` or use a `public partial class Program { }` marker).

### For SSE streaming endpoints

```csharp
[Fact]
public async Task Sse_StreamsEvents()
{
    var response = await _client.GetAsync("/mcp/sse",
        HttpCompletionOption.ResponseHeadersRead);

    using var stream = await response.Content.ReadAsStreamAsync();
    using var reader = new StreamReader(stream);

    var line = await reader.ReadLineAsync();
    Assert.StartsWith("event:", line);
}
```

This gives you full protocol-level coverage — real middleware, real routing, real serialization — with unit-test speed.
